-- NOVAMARKET TECH – BASE DE DATOS COMPLETA
-- Sesión 6: Modelo Relacional y SQL — Script completo (DDL + DML)
-- Dataset longitudinal del curso: Sep–Nov 2023, 500 transacciones
-- ═══════════════════════════════════════════════════════════════


-- ── LIMPIEZA (re-ejecución segura) ─────────────────────────────
DROP TABLE IF EXISTS FactVentas;
DROP TABLE IF EXISTS DimProducto;
DROP TABLE IF EXISTS DimCiudad;
DROP TABLE IF EXISTS DimFecha;

-- ── DDL: TABLAS DE DIMENSIÓN ────────────────────────────────────

CREATE TABLE DimProducto (
    ProductoID      INT          PRIMARY KEY,
    Nombre          VARCHAR(100) NOT NULL,
    Categoria       VARCHAR(50)  NOT NULL,
    Precio_Unitario DECIMAL(10,2) NOT NULL,
    Costo_Unitario  DECIMAL(10,2) NOT NULL
);

CREATE TABLE DimCiudad (
    CiudadID       INT          PRIMARY KEY,
    Nombre         VARCHAR(100) NOT NULL,
    Region         VARCHAR(50)  NOT NULL,
    Factor_Envio   DECIMAL(4,2) NOT NULL,
    Es_Zona_Remota TINYINT(1)   DEFAULT 0,
    Costo_Envio_Base DECIMAL(10,2) NOT NULL
);

CREATE TABLE DimFecha (
    FechaID        INT          PRIMARY KEY,
    Fecha          DATE         NOT NULL,
    Anio           INT          NOT NULL,
    Mes            INT          NOT NULL,
    NombreMes      VARCHAR(20)  NOT NULL,
    Trimestre      INT          NOT NULL,
    Semana         INT          NOT NULL,
    DiaSemana      VARCHAR(15)  NOT NULL,
    Es_FinSemana   TINYINT(1)   DEFAULT 0,
    Evento_Especial VARCHAR(50) NULL
);

CREATE TABLE FactVentas (
    TransaccionID  INT           PRIMARY KEY,
    FechaID        INT           NOT NULL,
    ProductoID     INT           NOT NULL,
    CiudadID       INT           NOT NULL,
    Cantidad       INT           NOT NULL CHECK (Cantidad > 0),
    Precio_Venta   DECIMAL(10,2) NOT NULL,
    Descuento_Pct  DECIMAL(5,4)  DEFAULT 0,
    Costo_Envio    DECIMAL(10,2) NOT NULL,
    CONSTRAINT fk_fecha   FOREIGN KEY (FechaID)    REFERENCES DimFecha(FechaID),
    CONSTRAINT fk_prod    FOREIGN KEY (ProductoID) REFERENCES DimProducto(ProductoID),
    CONSTRAINT fk_ciudad  FOREIGN KEY (CiudadID)   REFERENCES DimCiudad(CiudadID)
);

-- ── DML: INSERT DIMENSIONES ─────────────────────────────────────





-- ── VERIFICACIÓN ────────────────────────────────────────────────
SELECT 'DimProducto' AS Tabla, COUNT(*) AS Registros FROM DimProducto
UNION ALL SELECT 'DimCiudad',  COUNT(*) FROM DimCiudad
UNION ALL SELECT 'DimFecha',   COUNT(*) FROM DimFecha
UNION ALL SELECT 'FactVentas', COUNT(*) FROM FactVentas;

-- Resultado esperado:
-- DimProducto:  4 registros
-- DimCiudad:    6 registros
-- DimFecha:   91 registros (Sep-Nov 2023)
-- FactVentas: 500 registros